# =====================================================
MAX_ITEMS = 450
MAX_COST  = 900_000
MAX_ROWS  = 50_000
# SUFFIXES  = list(string.ascii_uppercase)

# -----------------------------------------------------
# Supports:
# A → Z
# AA → ZZ
# Total Variants = 702
# -----------------------------------------------------
SUFFIXES = (
    list(string.ascii_uppercase) +
    [
        a + b
        for a in string.ascii_uppercase
        for b in string.ascii_uppercase
    ]
)



